const users = new Map(); // socket.id -> pseudo

io.on('connection', (socket) => {
  socket.on('user_join', async (pseudo) => {
    users.set(socket.id, pseudo);
    // Envoyer historique
    const history = await Message.find({ receiver: null }).sort({ timestamp: -1 }).limit(50);
    socket.emit('history', history.reverse());
    io.emit('user_list', Array.from(users.values()));
  });

  socket.on('send_public', async (data) => {
    const message = new Message({ sender: data.pseudo, receiver: null, content: data.text });
    await message.save();
    io.emit('new_public', message);
  });

  socket.on('send_private', async ({ to, text }) => {
    const sender = users.get(socket.id);
    const targetSocketId = [...users.entries()].find(([_, pseudo]) => pseudo === to)?.[0];
    const message = new Message({ sender, receiver: to, content: text });
    await message.save();
    io.to(targetSocketId).emit('new_private', { from: sender, text });
    socket.emit('private_sent', { to, text });
  });

  socket.on('disconnect', () => {
    users.delete(socket.id);
    io.emit('user_list', Array.from(users.values()));
  });
});
```

